import{_ as d,o as e,c as o,ag as a}from"./chunks/framework.DTiDeF2Q.js";const b=JSON.parse('{"title":"Chmodエイリアス | Dotfiles (JA)","titleTemplate":":title","description":"chmodエイリアスでファイルとディレクトリの権限管理を簡素化。755、644などの一般的な権限パターンのクイックショートカット。","frontmatter":{"title":"Chmodエイリアス | Dotfiles","description":"chmodエイリアスでファイルとディレクトリの権限管理を簡素化。755、644などの一般的な権限パターンのクイックショートカット。","lang":"ja-JP","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Chmodエイリアス preview","canonical":"/ja/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Chmodエイリアス","pageType":"docs","schemaType":"WebPage","metaTitle":"Chmodエイリアス - Dotfiles (JP)","permalink":"/ja/aliases/chmod/","sidebar":true,"meta":[{"name":"keywords","content":"chmod aliases, file permissions, shell shortcuts, dotfiles, unix permissions"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Chmodエイリアス - Dotfiles"},{"name":"twitter:description","content":"chmodエイリアスでファイルとディレクトリの権限管理を簡素化。"},{"name":"og:title","content":"Chmodエイリアス - Dotfiles"},{"name":"og:description","content":"chmodエイリアスでファイルとディレクトリの権限管理を簡素化。"},{"name":"og:image:alt","content":"Dotfiles - シェルライフにフィットするシンプルな設計"},{"name":"og:locale","content":"ja_JP"}]},"headers":[],"relativePath":"ja/aliases/chmod/index.md","filePath":"ja/aliases/chmod/index.md","lastUpdated":1773010926000}'),r={name:"ja/aliases/chmod/index.md"};function c(h,t,i,s,n,l){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="chmodエイリアス" tabindex="-1">Chmodエイリアス <a class="header-anchor" href="#chmodエイリアス" aria-label="Permalink to &quot;Chmodエイリアス&quot;">​</a></h1><p>ファイルとディレクトリの権限管理のためのショートカット。</p><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><p>chmodエイリアスは、コマンドラインからファイルとディレクトリの権限を管理する効率的な方法を提供します。数値の権限コードを覚える代わりに、<code>chmod_755</code>や<code>chmod_u+x</code>のような直感的なエイリアスを使用して、必要なアクセスモードを素早く設定できます。</p><p>これらのエイリアスは<code>chmod.aliases.sh</code>で定義され、chezmoiによって自動的にロードされます。</p><h2 id="リファレンス" tabindex="-1">リファレンス <a class="header-anchor" href="#リファレンス" aria-label="Permalink to &quot;リファレンス&quot;">​</a></h2><h3 id="一般的な権限エイリアス" tabindex="-1">一般的な権限エイリアス <a class="header-anchor" href="#一般的な権限エイリアス" aria-label="Permalink to &quot;一般的な権限エイリアス&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>権限</th><th>説明</th></tr></thead><tbody><tr><td><code>chmod_000</code></td><td><code>----------</code></td><td>誰にも権限なし</td></tr><tr><td><code>chmod_400</code></td><td><code>r--------</code></td><td>所有者のみ読み取り専用</td></tr><tr><td><code>chmod_444</code></td><td><code>r--r--r--</code></td><td>全員読み取り専用</td></tr><tr><td><code>chmod_600</code></td><td><code>rw-------</code></td><td>所有者のみ読み書き</td></tr><tr><td><code>chmod_644</code></td><td><code>rw-r--r--</code></td><td>所有者は読み書き、他は読み取り専用</td></tr><tr><td><code>chmod_666</code></td><td><code>rw-rw-rw-</code></td><td>全員読み書き</td></tr><tr><td><code>chmod_755</code></td><td><code>rwxr-xr-x</code></td><td>所有者はフル、他は読み取り/実行</td></tr><tr><td><code>chmod_764</code></td><td><code>rwxrw-r--</code></td><td>所有者はフル、グループは読み書き</td></tr><tr><td><code>chmod_777</code></td><td><code>rwxrwxrwx</code></td><td>全員フル権限</td></tr></tbody></table><h3 id="所有者権限エイリアス" tabindex="-1">所有者権限エイリアス <a class="header-anchor" href="#所有者権限エイリアス" aria-label="Permalink to &quot;所有者権限エイリアス&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>説明</th></tr></thead><tbody><tr><td><code>chmod_u+x</code></td><td>所有者に実行権限を追加</td></tr><tr><td><code>chmod_u-x</code></td><td>所有者から実行権限を削除</td></tr><tr><td><code>chmod_u+w</code></td><td>所有者に書き込み権限を追加</td></tr><tr><td><code>chmod_u-w</code></td><td>所有者から書き込み権限を削除</td></tr><tr><td><code>chmod_u+r</code></td><td>所有者に読み取り権限を追加</td></tr><tr><td><code>chmod_u-r</code></td><td>所有者から読み取り権限を削除</td></tr></tbody></table><h3 id="グループ権限エイリアス" tabindex="-1">グループ権限エイリアス <a class="header-anchor" href="#グループ権限エイリアス" aria-label="Permalink to &quot;グループ権限エイリアス&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>説明</th></tr></thead><tbody><tr><td><code>chmod_g+x</code></td><td>グループに実行権限を追加</td></tr><tr><td><code>chmod_g-x</code></td><td>グループから実行権限を削除</td></tr><tr><td><code>chmod_g+w</code></td><td>グループに書き込み権限を追加</td></tr><tr><td><code>chmod_g-w</code></td><td>グループから書き込み権限を削除</td></tr><tr><td><code>chmod_g+r</code></td><td>グループに読み取り権限を追加</td></tr><tr><td><code>chmod_g-r</code></td><td>グループから読み取り権限を削除</td></tr></tbody></table><h3 id="その他の権限エイリアス" tabindex="-1">その他の権限エイリアス <a class="header-anchor" href="#その他の権限エイリアス" aria-label="Permalink to &quot;その他の権限エイリアス&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>説明</th></tr></thead><tbody><tr><td><code>chmod_o+x</code></td><td>その他に実行権限を追加</td></tr><tr><td><code>chmod_o-x</code></td><td>その他から実行権限を削除</td></tr><tr><td><code>chmod_o+w</code></td><td>その他に書き込み権限を追加</td></tr><tr><td><code>chmod_o-w</code></td><td>その他から書き込み権限を削除</td></tr><tr><td><code>chmod_o+r</code></td><td>その他に読み取り権限を追加</td></tr><tr><td><code>chmod_o-r</code></td><td>その他から読み取り権限を削除</td></tr></tbody></table><h3 id="ファイルタイプエイリアス" tabindex="-1">ファイルタイプエイリアス <a class="header-anchor" href="#ファイルタイプエイリアス" aria-label="Permalink to &quot;ファイルタイプエイリアス&quot;">​</a></h3><table tabindex="0"><thead><tr><th>エイリアス</th><th>説明</th></tr></thead><tbody><tr><td><code>chmod_755d</code></td><td>すべてのディレクトリの権限を<code>rwxr-xr-x</code>に設定</td></tr><tr><td><code>chmod_644f</code></td><td>すべてのファイルの権限を<code>rw-r--r--</code>に設定</td></tr></tbody></table><h3 id="再帰的権限関数" tabindex="-1">再帰的権限関数 <a class="header-anchor" href="#再帰的権限関数" aria-label="Permalink to &quot;再帰的権限関数&quot;">​</a></h3><p><code>change_permission</code>関数は、確認プロンプト付きで権限を再帰的に適用します：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">change_permission</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/directory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span></span></code></pre></div>',19)])])}const p=d(r,[["render",c]]);export{b as __pageData,p as default};
